mapper.select:
SELECT t.id, t.team, ct.competition_id, c.competition_name, t.create_time AS createTime, u_teacher.username AS teacher FROM team t INNER JOIN team_user tu ON t.id = tu.team_id LEFT JOIN user u_teacher ON t.teacher_id = u_teacher.id LEFT JOIN competition_team ct ON t.id = ct.team_id LEFT JOIN competition c ON ct.competition_id = c.id
tu.user_id = #{userId}
AND t.team LIKE CONCAT('%', #{team}, '%')
